esqlQuery.esql:
TS metrics-ibmmq.otel-*
| STATS expired_rate = SUM(RATE(ibmmq_qmgr_expired_message_total))
    BY attributes.qmgr
// Alert when messages are expiring before being consumed
// Any non-zero expiration rate indicates consumers are falling behind
// or message TTL settings are too aggressive
// Adjust threshold based on expected message expiration patterns
| WHERE expired_rate IS NOT NULL AND expired_rate > 0
